# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

class PasswordResetUniversalLinkHandler: NSObject, UNNotificationDelegate {
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplicationLaunchOptionsKey: Any]?) -> Bool {
        let supportedTypes = Set([UNNotificationType.remote])
        let center = UNUserNotificationCenter.current()
        center.delegate = self
        center.setNotificationCategories(Set([UNNotificationCategory(identifier: "passwordReset", actions: [], intentIdentifiers: [])]))
        return true
    }
    
    func userNotificationCenter(_ center: UNUserNotificationCenter, didReceive response: UNNotificationResponse, withCompletionHandler completionHandler: @escaping () -> Void) {
        if response.notification.request.content.categoryIdentifier == "passwordReset" {
            let token = response.notification.request.content.userInfo["token"] as? String
            navigateToPasswordResetScreen(withToken: token)
        }
        completionHandler()
    }
    
    func navigateToPasswordResetScreen(withToken token: String?) {
        guard let token = token else { return }
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        let resetPasswordViewController = storyboard.instantiateViewController(withIdentifier: "ResetPasswordViewController") as! ResetPasswordViewController
        resetPasswordViewController.token = token
        navigationController?.pushViewController(resetPasswordViewController, animated: true)
    }
}